import { readFile, writeFile } from "node:fs/promises";
import { createRequire } from "node:module";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const rootDir = dirname(dirname(fileURLToPath(import.meta.url)));
const require = createRequire(import.meta.url);
const moduleFiles = require("./app-module-files.cjs");

const chunks = await Promise.all(
  moduleFiles.map(async (relativePath) => {
    const source = await readFile(join(rootDir, relativePath), "utf8");
    return `\n// ---- ${relativePath} ----\n${source.trim()}\n`;
  }),
);

const banner = [
  '"use strict";',
  "// Generated by scripts/build-js-bundle.mjs. Edit source modules instead.",
  "",
].join("\n");

await writeFile(join(rootDir, "js/app.bundle.js"), `${banner}${chunks.join("")}\n`, "utf8");
